CREATE FUNCTION app.rewind_notification() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
    BEGIN
      IF TG_OP = 'INSERT' THEN
        PERFORM pg_notify(
          '0xf633c0b3e32eb904',
          format('{"event":"%s","chainId":"%s"}', 'rewind', NEW."chainId")
        );
      ELSIF TG_OP = 'UPDATE' THEN
        IF NEW.status = 'complete' THEN
          PERFORM pg_notify(
            '0xf633c0b3e32eb904',
            format('{"event":"%s","chainId":"%s"}', 'rewind_complete', NEW."chainId")
          );
        ELSIF NEW."rewindTimestamp" < OLD."rewindTimestamp" THEN
          PERFORM pg_notify(
            '0xf633c0b3e32eb904',
            format('{"event":"%s","chainId":"%s"}', 'timestamp_decreased', NEW."chainId")
          );
        END IF;
      ELSIF TG_OP = 'DELETE' THEN
        PERFORM pg_notify(
          '0xf633c0b3e32eb904',
          format('{"event":"%s","chainId":"%s"}', 'fully_rewind', OLD."chainId")
        );
      END IF;

      RETURN NULL;
    END;
    $$;


